(async () => {
  const nowStr = await api.getCurrentDatetime();
  const now = nowStr ? new Date(nowStr) : new Date();
  const from = new Date(now);
  from.setDate(now.getDate() - 7);
  const fromIso = from.toISOString();
  const toIso = now.toISOString();
  const customers = await api.getAllCustomers({ limit: 5000, offset: 0 });
  let best = null;
  for (const cust of customers) {
    const stats = await api.computeCustomerSpendStats({ customerId: cust.id, fromIso, toIso });
    const { transactionCount, totalSpend } = stats;
    if (transactionCount === undefined || totalSpend === undefined) continue;
    const averageSpend = transactionCount > 0 ? totalSpend / transactionCount : 0;
    if (!best || transactionCount > best.transactionCount) {
      best = {
        topCustomerId: cust.id,
        topCustomerName: cust.name,
        transactionCount,
        totalSpend,
        averageSpend,
        fromIso,
        toIso,
      };
    }
  }
  return best;
})();

